fn solve(value: Vec<i64>, limit: Vec<i64>) -> i64 {
    // Sort elements by value in descending order to prioritize higher values
    let mut elements = value.into_iter().zip(limit.into_iter()).collect::<Vec<_>>();
    elements.sort_by(|a, b| b.0.cmp(&a.0));

    let mut active_count = 0;
    let mut total_sum = 0;
    let mut activated = std::collections::HashSet::new();

    for (val, lim) in elements {
        // Check if the element can be activated based on current active count
        if active_count < lim && !activated.contains(&lim) {
            // Activate the element
            total_sum += val;
            activated.insert(lim);
            active_count += 1;
        }
    }

    total_sum
}
