function solve(value: number[], limit: number[]): number {
    // Sort elements by value in descending order to prioritize higher values
    const elements = value.map((v, i) => ({ value: v, limit: limit[i] })).sort((a, b) => b.value - a.value);

    let activeCount = 0;
    let totalSum = 0;
    const activated = new Set<number>();

    for (const elem of elements) {
        // Check if the element can be activated based on current active count
        if (activeCount < elem.limit && !activated.has(elem.limit)) {
            // Activate the element
            totalSum += elem.value;
            activated.add(elem.limit);
            activeCount++;
        }
    }

    return totalSum;
}
